pub fn closed_non_user_segments(messages: &[ChatMessage]) -> Vec<SummarySegment> {
    let user_indices: Vec<usize> = messages
        .iter()
        .enumerate()
        .filter_map(|(idx, msg)| (msg.role == "user").then_some(idx))
        .collect();
    if user_indices.len() < 2 {
        return Vec::new();
    }

